INSERT INTO `blog_article` VALUES (1,'Spring Boot + Vue.js 全栈开发实战','本文介绍如何使用Spring Boot和Vue.js构建现代化的全栈Web应用','# Spring Boot + Vue.js 全栈开发实战\n\n## 项目介绍\n本项目是基于Spring Boot 2.5.15和Vue.js 3.x构建的现代化博客系统。\n\n## 技术栈\n- 后端：Spring Boot + MyBatis + MySQL + Redis\n- 前端：Vue.js + Element Plus + Vite\n\n## 功能特性\n1. 用户管理\n2. 文章管理\n3. 分类标签\n4. 评论系统\n5. 权限控制\n\n## 总结\n通过本项目的实践，可以深入理解前后端分离开发的完整流程。','',1,1,1,1,1,13,0,0,'2025-10-14 11:54:48','2025-10-20 16:48:34',0),(2,'MySQL数据库优化实践','分享MySQL数据库性能优化的实用技巧和经验','# MySQL数据库优化实践\n\n## 索引优化\n合理使用索引可以大幅提升查询性能。\n\n## 查询优化\n避免全表扫描，优化SQL语句结构。\n\n## 配置优化\n调整MySQL配置参数，提升整体性能。','',1,1,0,1,1,17,0,0,'2025-10-14 11:54:48','2025-10-20 17:28:29',0),(3,'Vue.js 3.0 新特性详解','深入了解Vue.js 3.0的Composition API等新特性','# Vue.js 3.0 新特性详解\n\n## Composition API\n新的组合式API提供了更好的逻辑复用能力。\n\n## 性能提升\nVue 3在性能方面有显著提升。\n\n## TypeScript支持\n更好的TypeScript集成。','',1,1,0,0,1,5,0,0,'2025-10-14 11:54:48','2025-10-20 16:48:38',0),(8,'历史首次！首片blackwell晶圆在美国生产制造 仍需运回台积电总部封装','','快科技10月19日消息，当地时间周五，<strong>NVIDIA和台积电在共同宣布达成一项重要里程碑。 双方已在亚利桑那州凤凰城附近Fab 21工厂成功制造出第一款量产的Blackwell晶圆。</strong>这款堪称全球最复杂的芯片能在美国实现生产，对两家企业而言兼具战略、象征等重要意义。NVIDIA CEO黄仁勋在纪念活动上表示：<strong>“这是一个具有历史意义的时刻，原因有很多。这是近代美国历史上首次，由最先进的晶圆厂——台积电在美国本土，生产出全球最为关键的芯片。</strong>这践行了总统提出的再工业化愿景，<strong>即将制造业带回美国，创造就业岗位。同时，这也是全球至关重要的制造业领域，更是最核心的科技产业。</strong>”据悉，此次在美国生产的是Blackwell&nbsp;B300芯片（尚未得到官方确认），采用台积电为英伟达定制的4N制程（属于4nm级工艺节点）。这一成果意味着台积电Fab 21工厂已具备量产此类大型芯片的能力，且良率表现良好（据悉良率达标耗费了不少时间）。战略层面，这一突破实现了美国政府产业政策的核心目标，将更先进的半导体制造能力带回美国本土。对NVIDIA而言，其核心产品能在美国生产，可有效规避相关风险。据悉，台积电计划进一步扩建亚利桑那州Fab 21工厂，后续将在此量产采用N3、N2、A16及A14制程工艺的芯片。不过需要注意的是，<strong>尽管Blackwell芯片已实现美国本土制造，但要组装成完整的NVIDIA B300 GPU，仍需将这些晶圆运回台积电台湾工厂通过CoWoS-L先进封装技术与HBM3E内存进行整合。</strong>这也导致该款芯片的成本高于中国台湾本土生产的产品，仅保留了象征意义。','',2,1,0,0,1,1,0,0,'2025-10-20 16:11:27','2025-10-20 17:28:31',0),(9,'华为的atlas 300i duo ai推理加速卡','','快科技10月19日消息，Gamers Nexus通过特殊渠道拿到了一块<strong>华为的Atlas 300I DUO AI推理加速卡</strong>，特殊的双芯设计，搭载了两颗GPU，同时单插槽设计，身材轻盈。该卡没有公开售价，<strong>外媒花了1400美元，约合人民币1万元</strong>，可以说非常便宜了，国内批量采购价自然更低。根据华为官方说法，Atlas 300I Duo推理<strong>卡融合“通用处理器、AI核心、编解码”于一体，提供AI推理、视频分析等功能，具有超强算力、超高能效、高性能视频分析等优势</strong>，可广泛应用于互联网、智慧城市、智慧交通等多场景，支持检索聚类、内容审核、OCR识别、语音分析、视频分析等多应用。<strong>它搭载了两颗GPU核心，共有16个核心，主频1.9GHz，48GB或者96GB LPDDR4X ECC内存，总带宽408GB/s。</strong>系统接口为<strong>PCIe 4.0 x8</strong>，单插位全高全长设计，厚度仅为18.46毫米，<strong>功耗150W。</strong><strong>AI算力INT8格式下为80 TOPS，FP16格式下为140 TFLOPS，能效比高达1.86TOPS/W。</strong>视频编解码能力支持256路1080p30或32路4K60 H.264/H.264解码、48路1080p30或6路4K60 H.264/H.265视频编码、4K768 JPEG编码、4K384 JPEG解码，最高分辨率8192 x 8192。','',2,1,0,0,1,1,0,0,'2025-10-20 16:34:59','2025-10-20 17:28:25',0);
/*!40000 ALTER TABLE `blog_article` ENABLE KEYS */;
